INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000701, 'single', '90007', '下列何者「違反」個人資料保護法？', '公司基於人事管理之特定目的，張 貼榮譽榜揭示績優員工姓名,縣市政府提供村里長轄區內符合資格之老人 名冊供發放敬老金,網路購物公司為辦理退貨，將客戶之住家地址提供予 宅配公司,學校將應屆畢業生之住家地址提供補習班招生使用 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000702, 'single', '90007', '非公務機關利用個人資料進行行銷時，下列敘述何者「錯誤」？', '若已取 得當事人書面同意，當事人即不得拒絕利用其個人資料行銷,於首次行銷 時，應提供當事人表示拒絕行銷之方式,當事人表示拒絕接受行銷時，應 停止利用其個人資料,倘非公務機關違反「應即停止利用其個人資料行 銷」之義務，未於限期內改正者，按次處新臺幣2 萬元以上20 萬元以下 罰鍰 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000703, 'single', '90007', '個人資料保護法規定為保護當事人權益，多少位以上的當事人提出告訴， 就可以進行團體訴訟？', '5 人,10 人,15 人,20 人 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000704, 'single', '90007', '關於個人資料保護法之敘述，下列何者「錯誤」？', '公務機關執行法定職 務必要範圍內，可以蒐集、處理或利用一般性個人資料,間接蒐集之個人 資料，於處理或利用前，不必告知當事人個人資料來源,非公務機關亦應 維護個人資料之正確，並主動或依當事人之請求更正或補充,外國學生在 臺灣短期進修或留學，也受到我國個人資料保護法的保障 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000705, 'single', '90007', '下列關於個人資料保護法的敘述，下列敘述何者錯誤？', '不管是否使用電 腦處理的個人資料，都受個人資料保護法保護,公務機關依法執行公權 力，不受個人資料保護法規範,身分證字號、婚姻、指紋都是個人資料,我的病歷資料雖然是由醫生所撰寫，但也屬於是我的個人資料範圍 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000706, 'single', '90007', '對於依照個人資料保護法應告知之事項，下列何者不在法定應告知的事項 內？', '個人資料利用之期間、地區、對象及方式,蒐集之目的,蒐集機 關的負責人姓名,如拒絕提供或提供不正確個人資料將造成之影響 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000707, 'single', '90007', '請問下列何者非為個人資料保護法第3 條所規範之當事人權利？', '查詢或 請求閱覽,請求刪除他人之資料,請求補充或更正,請求停止蒐集、處 理或利用 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000708, 'single', '90007', '下列何者非安全使用電腦內的個人資料檔案的做法？', '利用帳號與密碼登 入機制來管理可以存取個資者的人,規範不同人員可讀取的個人資料檔案 範圍,個人資料檔案使用完畢後立即退出應用程式，不得留置於電腦中,為確保重要的個人資料可即時取得，將登入密碼標示在螢幕下方 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000709, 'single', '90007', '下列何者行為非屬個人資料保護法所稱之國際傳輸？', '將個人資料傳送給 經濟部,將個人資料傳送給美國的分公司,將個人資料傳送給法國的人 事部門,將個人資料傳送給日本的委託公司 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000710, 'single', '90007', '下列有關智慧財產權行為之敘述，何者有誤？', '製造、販售仿冒註冊商標 的商品不屬於公訴罪之範疇，但已侵害商標權之行為,以101 大樓、美麗 華百貨公司做為拍攝電影的背景，屬於合理使用的範圍,原作者自行創作 某音樂作品後，即可宣稱擁有該作品之著作權,著作權是為促進文化發展 為目的，所保護的財產權之一 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000711, 'single', '90007', '專利權又可區分為發明、新型與設計三種專利權，其中發明專利權是否有 保護期限？期限為何？', '有，5 年,有，20 年,有，50 年,無期限， 只要申請後就永久歸申請人所有 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000712, 'single', '90007', '受僱人於職務上所完成之著作，如果沒有特別以契約約定，其著作人為下 列何者？', '雇用人,受僱人,雇用公司或機關法人代表,由雇用人指定 之自然人或法人 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000713, 'single', '90007', '任職於某公司的程式設計工程師，因職務所編寫之電腦程式，如果沒有特 別以契約約定，則該電腦程式重製之權利歸屬下列何者？', '公司,編寫 程式之工程師,公司全體股東共有,公司與編寫程式之工程師共有 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000714, 'single', '90007', '某公司員工因執行業務，擅自以重製之方法侵害他人之著作財產權，若被 害人提起告訴，下列對於處罰對象的敘述，何者正確？', '僅處罰侵犯他人 著作財產權之員工,僅處罰雇用該名員工的公司,該名員工及其雇主皆 須受罰,員工只要在從事侵犯他人著作財產權之行為前請示雇主並獲同 意，便可以不受處罰 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000715, 'single', '90007', '受僱人於職務上所完成之發明、新型或設計，其專利申請權及專利權如未 特別約定屬於下列何者？', '雇用人,受僱人,雇用人所指定之自然人或 法人,雇用人與受僱人共有 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000716, 'single', '90007', '任職大發公司的郝聰明，專門從事技術研發，有關研發技術的專利申請權 及專利權歸屬，下列敘述何者錯誤？', '職務上所完成的發明，除契約另有 約定外，專利申請權及專利權屬於大發公司,職務上所完成的發明，雖然 專利申請權及專利權屬於大發公司，但是郝聰明享有姓名表示權,郝聰明 完成非職務上的發明，應即以書面通知大發公司,大發公司與郝聰明之雇 傭契約約定，郝聰明非職務上的發明，全部屬於公司，約定有效 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000717, 'single', '90007', '有關著作權的下列敘述何者不正確？', '我們到表演場所觀看表演時，不可 隨便錄音或錄影,到攝影展上，拿相機拍攝展示的作品，分贈給朋友，是 侵害著作權的行為,網路上供人下載的免費軟體，都不受著作權法保護， 所以我可以燒成大補帖光碟，再去賣給別人,高普考試題，不受著作權法 保護 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000718, 'single', '90007', '有關著作權的下列敘述何者錯誤？', '撰寫碩博士論文時，在合理範圍內引 用他人的著作，只要註明出處，不會構成侵害著作權,在網路散布盜版光 碟，不管有沒有營利，會構成侵害著作權,在網路的部落格看到一篇文章 很棒，只要註明出處，就可以把文章複製在自己的部落格,將補習班老師 的上課內容錄音檔，放到網路上拍賣，會構成侵害著作權 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000719, 'single', '90007', '有關商標權的下列敘述何者錯誤？', '要取得商標權一定要申請商標註冊,商標註冊後可取得10 年商標權,商標註冊後，3 年不使用，會被廢止 商標權,在夜市買的仿冒品，品質不好，上網拍賣，不會構成侵權 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000720, 'single', '90007', '下列關於營業秘密的敘述，何者不正確？', '受雇人於非職務上研究或開發 之營業秘密，仍歸雇用人所有,營業秘密不得為質權及強制執行之標的,營業秘密所有人得授權他人使用其營業秘密,營業秘密得全部或部分讓 與他人或與他人共有 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000721, 'single', '90007', '甲公司將其新開發受營業秘密法保護之技術，授權乙公司使用，下列何者 不得為之？', '乙公司已獲授權，所以可以未經甲公司同意，再授權丙公司 使用,約定授權使用限於一定之地域、時間,約定授權使用限於特定之 內容、一定之使用方法,要求被授權人乙公司在一定期間負有保密義 務 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000722, 'single', '90007', '甲公司嚴格保密之最新配方產品大賣，下列何者侵害甲公司之營業秘密？', '鑑定人A 因司法審理而知悉配方,甲公司授權乙公司使用其配方,甲 公司之B 員工擅自將配方盜賣給乙公司,甲公司與乙公司協議共有配 方 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000723, 'single', '90007', '故意侵害他人之營業秘密，法院因被害人之請求，最高得酌定損害額幾倍 之賠償？', '1 倍,2 倍,3 倍,4 倍 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000724, 'single', '90007', '受雇者因承辦業務而知悉營業秘密，在離職後對於該營業秘密的處理方 式，下列敘述何者正確？', '聘雇關係解除後便不再負有保障營業秘密之責,僅能自用而不得販售獲取利益,自離職日起3 年後便不再負有保障營業 秘密之責,離職後仍不得洩漏該營業秘密 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000725, 'single', '90007', '按照現行法律規定，侵害他人營業秘密，其法律責任為：', '僅需負刑事責 任,僅需負民事損害賠償責任,刑事責任與民事損害賠償責任皆須負擔,刑事責任與民事損害賠償責任皆不須負擔 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000726, 'single', '90007', '企業內部之營業秘密，可以概分為「商業性營業秘密」及「技術性營業秘 密」二大類型，請問下列何者屬於「技術性營業秘密」？', '人事管理,經銷據點,產品配方,客戶名單 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000727, 'single', '90007', '某離職同事請求在職員工將離職前所製作之某份文件傳送給他，請問下列 回應方式何者正確？', '由於該項文件係由該離職員工製作，因此可以傳送 文件,若其目的僅為保留檔案備份，便可以傳送文件,可能構成對於營 業秘密之侵害，應予拒絕並請他直接向公司提出請求,視彼此交情決定是 否傳送文件 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000728, 'single', '90007', '行為人以竊取等不正當方法取得營業秘密，下列敘述何者正確？', '已構成 犯罪,只要後續沒有洩漏便不構成犯罪,只要後續沒有出現使用之行為 便不構成犯罪,只要後續沒有造成所有人之損害便不構成犯罪 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000729, 'single', '90007', '針對在我國境內竊取營業秘密後，意圖在外國、中國大陸或港澳地區使用 者，營業秘密法是否可以適用？', '無法適用,可以適用，但若屬未遂犯 則不罰,可以適用並加重其刑,能否適用需視該國家或地區與我國是否 簽訂相互保護營業秘密之條約或協定 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000730, 'single', '90007', '所謂營業秘密，係指方法、技術、製程、配方、程式、設計或其他可用於 生產、銷售或經營之資訊，但其保障所需符合的要件不包括下列何者？', '因其秘密性而具有實際之經濟價值者,所有人已採取合理之保密措施者,因其秘密性而具有潛在之經濟價值者,一般涉及該類資訊之人所知 者 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000731, 'single', '90007', '因故意或過失而不法侵害他人之營業秘密者，負損害賠償責任該損害賠償 之請求權，自請求權人知有行為及賠償義務人時起，幾年間不行使就會消 滅？', '2 年,5 年,7 年,10 年 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000732, 'single', '90007', '公司負責人為了要節省開銷，將員工薪資以高報低來投保全民健保及勞 保，是觸犯了刑法上之何種罪刑？', '詐欺罪,侵占罪,背信罪,工商秘 密罪 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000733, 'single', '90007', 'A 受僱於公司擔任會計，因自己的財務陷入危機，多次將公司帳款轉入妻 兒戶頭，是觸犯了刑法上之何種罪刑？', '洩漏工商秘密罪,侵占罪,詐 欺罪,偽造文書罪 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000734, 'single', '90007', '某甲於公司擔任業務經理時，未依規定經董事會同意，私自與自己親友之 公司訂定生意合約，會觸犯下列何種罪刑？', '侵占罪,貪污罪,背信罪,詐欺罪 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000735, 'single', '90007', '如果你擔任公司採購的職務，親朋好友們會向你推銷自家的產品，希望你 要採購時，你應該', '適時地婉拒，說明利益需要迴避的考量，請他們見諒,既然是親朋好友，就應該互相幫忙,建議親朋好友將產品折扣，折扣部 分歸於自己，就會採購,可以暗中地幫忙親朋好友，進行採購，不要被發 現有親友關係便可 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000736, 'single', '90007', '小美是公司的業務經理，有一天巧遇國中同班的死黨小林，發現他是公司 的下游廠商老闆。最近小美處理一件公司的招標案件，小林的公司也在其 中，私下約小美見面，請求她提供這次招標案的底標，並馬上要給予幾十 萬元的前謝金，請問小美該怎麼辦？', '退回錢，並告訴小林都是老朋友， 一定會全力幫忙,收下錢，將錢拿出來給單位同事們分紅,應該堅決拒 絕，並避免每次見面都與小林談論相關業務問題,朋友一場，給他一個比 較接近底標的金額，反正又不是正確的，所以沒關係 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000737, 'single', '90007', '公司發給每人一台平板電腦提供業務上使用，但是發現根本很少在使用， 為了讓它有效的利用，所以將它拿回家給親人使用，這樣的行為是', '可以 的，這樣就不用花錢買,可以的，反正放在那裡不用它，也是浪費資源,不可以的，因為這是公司的財產，不能私用,不可以的，因為使用年限 未到，如果年限到報廢了，便可以拿回家 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000738, 'single', '90007', '公司的車子，假日又沒人使用，你是鑰匙保管者，請問假日可以開出去 嗎？', '可以，只要付費加油即可,可以，反正假日不影響公務,不可 以，因為是公司的，並非私人擁有,不可以，應該是讓公司想要使用的員 工，輪流使用才可 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000739, 'single', '90007', '阿哲是財經線的新聞記者，某次採訪中得知A 公司在一個月內將有一個大 的併購案，這個併購案顯示公司的財力，且能讓A 公司股價往上飆升。請 問阿哲得知此消息後，可以立刻購買該公司的股票嗎？', '可以，有錢大家 賺,可以，這是我努力獲得的消息,可以，不賺白不賺,不可以，屬於 內線消息，必須保持記者之操守，不得洩漏 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000740, 'single', '90007', '與公務機關接洽業務時，下列敘述何者「正確」？', '沒有要求公務員違背 職務，花錢疏通而已，並不違法,唆使公務機關承辦採購人員配合浮報價 額，僅屬偽造文書行為,口頭允諾行賄金額但還沒送錢，尚不構成犯罪,與公務員同謀之共犯，即便不具公務員身分，仍可依據貪污治罪條例處 刑 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000741, 'single', '90007', '與公務機關有業務往來構成職務利害關係者，下列敘述何者「正確」？', '將餽贈之財物請公務員父母代轉，該公務員亦已違反規定,與公務機關承 辦人飲宴應酬為增進基本關係的必要方法,高級茶葉低價售予有利害關係 之承辦公務員，有價購行為就不算違反法規,機關公務員藉子女婚宴廣邀 業務往來廠商之行為，並無不妥 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000742, 'single', '90007', '廠商某甲承攬公共工程，工程進行期間，甲與其工程人員經常招待該公共 工程委辦機關之監工及驗收之公務員喝花酒或招待出國旅遊，下列敘述何 者正確？', '公務員若沒有收現金，就沒有罪,只要工程沒有問題，某甲 與監工及驗收等相關公務員就沒有犯罪,因為不是送錢，所以都沒有犯罪,某甲與相關公務員均已涉嫌觸犯貪污治罪條例 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000743, 'single', '90007', '行（受）賄罪成立要素之一為具有對價關係，而作為公務員職務之對價有 「賄賂」或「不正利益」，下列何者「不」屬於「賄賂」或「不正利 益」？', '開工邀請公務員觀禮,送百貨公司大額禮券,免除債務,招待 吃米其林等級之高檔大餐 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000744, 'single', '90007', '下列有關貪腐的敘述何者錯誤？', '貪腐會危害永續發展和法治,貪腐會 破壞民主體制及價值觀,貪腐會破壞倫理道德與正義,貪腐有助降低企 業的經營成本 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000745, 'single', '90007', '下列何者不是設置反貪腐專責機構須具備的必要條件？', '賦予該機構必要 的獨立性,使該機構的工作人員行使職權不會受到不當干預,提供該機 構必要的資源、專職工作人員及必要培訓,賦予該機構的工作人員有權力 可隨時逮捕貪污嫌疑人 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000746, 'single', '90007', '檢舉人向有偵查權機關或政風機構檢舉貪污瀆職，必須於何時為之始可能 給與獎金？', '犯罪未起訴前,犯罪未發覺前,犯罪未遂前,預備犯罪 前 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000747, 'single', '90007', '檢舉人應以何種方式檢舉貪污瀆職始能核給獎金？', '匿名,委託他人檢 舉,以真實姓名檢舉,以他人名義檢舉 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000748, 'single', '90007', '我國制定何種法律以保護刑事案件之證人，使其勇於出面作證，俾利犯罪 之偵查、審判？', '貪污治罪條例,刑事訴訟法,行政程序法,證人保護 法 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000749, 'single', '90007', '下列何者「非」屬公司對於企業社會責任實踐之原則？', '加強個人資料揭 露,維護社會公益,發展永續環境,落實公司治理 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000750, 'single', '90007', '下列何者「不」屬於職業素養的範疇？', '獲利能力,正確的職業價值觀,職業知識技能,良好的職業行為習慣 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000751, 'single', '90007', '下列何者符合專業人員的職業道德？', '未經雇主同意，於上班時間從事私 人事務,利用雇主的機具設備私自接單生產,未經顧客同意，任意散佈 或利用顧客資料,盡力維護雇主及客戶的權益 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000752, 'single', '90007', '身為公司員工必須維護公司利益，下列何者是正確的工作態度或行為？', '將公司逾期的產品更改標籤,施工時以省時、省料為獲利首要考量，不顧 品質,服務時首先考慮公司的利益，然後再考量顧客權益,工作時謹守 本分，以積極態度解決問題 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000753, 'single', '90007', '身為專業技術工作人士，應以何種認知及態度服務客戶？', '若客戶不瞭 解，就儘量減少成本支出，抬高報價,遇到維修問題，儘量拖過保固期,主動告知可能碰到問題及預防方法,隨著個人心情來提供服務的內容及 品質 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000754, 'single', '90007', '因為工作本身需要高度專業技術及知識，所以在對客戶服務時應如何？', '不用理會顧客的意見,保持親切、真誠、客戶至上的態度,若價錢較 低，就敷衍了事,以專業機密為由，不用對客戶說明及解釋 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000755, 'single', '90007', '從事專業性工作，在與客戶約定時間應', '保持彈性，任意調整,儘可能 準時，依約定時間完成工作,能拖就拖，能改就改,自己方便就好，不 必理會客戶的要求 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000756, 'single', '90007', '從事專業性工作，在服務顧客時應有的態度為何？', '選擇最安全、經濟及 有效的方法完成工作,選擇工時較長、獲利較多的方法服務客戶,為了 降低成本，可以降低安全標準,不必顧及雇主和顧客的立場 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000757, 'single', '90007', '以下那一項員工的作為符合敬業精神？', '利用正常工作時間從事私人事務,運用雇主的資源，從事個人工作,未經雇主同意擅離工作崗位,謹守 職場紀律及禮節，尊重客戶隱私 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000758, 'single', '90007', '小張獲選為小孩學校的家長會長，這個月要召開會議，沒時間準備資料， 所以，利用上班期間有空檔非休息時間來完成，請問是否可以？', '可以， 因為不耽誤他的工作,可以，因為他能力好，能夠同時完成很多事,不 可以，因為這是私事，不可以利用上班時間完成,可以，只要不要被發 現 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000759, 'single', '90007', '小吳是公司的專用司機，為了能夠隨時用車，經過公司同意，每晚都將公 司的車開回家，然而，他發現反正每天上班路線，都要經過女兒學校，就 順便載女兒上學，請問可以嗎？', '可以，反正順路,不可以，這是公司 的車不能私用,可以，只要不被公司發現即可,可以，要資源須有效使 用 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000760, 'single', '90007', '彥江是職場上的新鮮人，剛進公司不久，他應該具備怎樣的態度', '上班、 下班，管好自己便可,仔細觀察公司生態，加入某些小團體，以做為後盾,只要做好人脈關係，這樣以後就好辦事,努力做好自己職掌的業務，樂 於工作，與同事之間有良好的互動，相互協助 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000761, 'single', '90007', '在公司內部行使商務禮儀的過程，主要以參與者在公司中的何種條件來訂 定順序？', '年齡,性別,社會地位,職位 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000762, 'single', '90007', '一位職場新鮮人剛進公司時，良好的工作態度是', '多觀察、多學習，了解 企業文化和價值觀,多打聽哪一個部門比較輕鬆，升遷機會較多,多探 聽哪一個公司在找人，隨時準備跳槽走人,多遊走各部門認識同事，建立 自己的小圈圈 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000763, 'single', '90007', '根據消除對婦女一切形式歧視公約(CEDAW)，下列何者正確？', '對婦女 的歧視指基於性別而作的任何區別、排斥或限制,只關心女性在政治方面 的人權和基本自由,未要求政府需消除個人或企業對女性的歧視,傳統 習俗應予保護及傳承，即使含有歧視女性的部分，也不可以改變 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000764, 'single', '90007', '某規範明定地政機關進用女性測量助理名額，不得超過該機關測量助理名 額總數二分之一，根據消除對婦女一切形式歧視公約(CEDAW)，下列何者 正確？', '限制女性測量助理人數比例，屬於直接歧視,土地測量經常在 戶外工作，基於保護女性所作的限制，不屬性別歧視,此項二分之一規定 是為促進男女比例平衡,此限制是為確保機關業務順暢推動，並未歧視女 性 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000765, 'single', '90007', '根據消除對婦女一切形式歧視公約(CEDAW)之間接歧視意涵，下列何者錯 誤？', '一項法律、政策、方案或措施表面上對男性和女性無任何歧視，但 實際上卻產生歧視女性的效果,察覺間接歧視的一個方法，是善加利用性 別統計與性別分析,如果未正視歧視之結構和歷史模式，及忽略男女權力 關係之不平等，可能使現有不平等狀況更為惡化,不論在任何情況下，只 要以相同方式對待男性和女性，就能避免間接歧視之產生 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000766, 'single', '90007', '下列何者「不是」菸害防制法之立法目的？', '防制菸害,保護未成年免 於菸害,保護孕婦免於菸害,促進菸品的使用 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000767, 'single', '90007', '按菸害防制法規定，對於在禁菸場所吸菸會被罰多少錢？', '新臺幣2 千元 至1 萬元罰鍰,新臺幣1 千元至5 千元罰鍰,新臺幣1 萬元至5 萬元罰 鍰,新臺幣2 萬元至10 萬元罰鍰 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000768, 'single', '90007', '請問下列何者「不是」個人資料保護法所定義的個人資料？', '身分證號碼,最高學歷,職稱,護照號碼 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000769, 'single', '90007', '有關專利權的敘述，何者正確？', '專利有規定保護年限，當某商品、技術 的專利保護年限屆滿，任何人皆可免費運用該項專利,我發明了某項商 品，卻被他人率先申請專利權，我仍可主張擁有這項商品的專利權,製造 方法可以申請新型專利權,在本國申請專利之商品進軍國外，不需向他國 申請專利權 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000770, 'single', '90007', '下列何者行為會有侵害著作權的問題？', '將報導事件事實的新聞文字轉貼 於自己的社群網站,直接轉貼高普考考古題在FACEBOOK,以分享網址 的方式轉貼資訊分享於社群網站,將講師的授課內容錄音，複製多份分贈 友人 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000771, 'single', '90007', '下列有關著作權之概念，何者正確？', '國外學者之著作，可受我國著作權 法的保護,公務機關所函頒之公文，受我國著作權法的保護,著作權要 待向智慧財產權申請通過後才可主張,以傳達事實之新聞報導的語文著 作，依然受著作權之保障 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000772, 'single', '90007', '某廠商之商標在我國已經獲准註冊，請問若希望將商品行銷販賣到國外， 請問是否需在當地申請註冊才能主張商標權？', '是，因為商標權註冊採取 屬地保護原則,否，因為我國申請註冊之商標權在國外也會受到承認,不一定，需視我國是否與商品希望行銷販賣的國家訂有相互商標承認之協 定,不一定，需視商品希望行銷販賣的國家是否為WTO 會員國 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000773, 'single', '90007', '下列何者「非」屬於營業秘密？', '具廣告性質的不動產交易底價,須授 權取得之產品設計或開發流程圖示,公司內部管制的各種計畫方案,不 是公開可查知的客戶名單分析資料 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000774, 'single', '90007', '營業秘密可分為「技術機密」與「商業機密」，下列何者屬於「商業機 密」？', '程式,設計圖,商業策略,生產製程 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000775, 'single', '90007', '某甲在公務機關擔任首長，其弟弟乙是某協會的理事長，乙為舉辦協會活 動，決定向甲服務的機關申請經費補助，下列有關利益衝突迴避之敘述， 何者正確？', '協會是舉辦慈善活動，甲認為是好事，所以指示機關承辦人 補助活動經費,機關未經公開公平方式，私下直接對協會補助活動經費新 臺幣10 萬元,甲應自行迴避該案審查，避免瓜田李下，防止利益衝突,乙為順利取得補助，應該隱瞞是機關首長甲之弟弟的身分 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000776, 'single', '90007', '依公職人員利益衝突迴避法規定，公職人員甲與其小舅子乙（二親等以內 的關係人）間，下列何種行為不違反該法？', '甲要求受其監督之機關聘用 小舅子乙,小舅子乙以請託關說之方式，請求甲之服務機關通過其名下農 地變更使用申請案,關係人乙經政府採購法公開招標程序，並主動在投標 文件表明與甲的身分關係，取得甲服務機關之年度採購標案,甲、乙兩人 均自認為人公正，處事坦蕩，任何往來都是清者自清，不需擔心任何問 題 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000777, 'single', '90007', '大雄擔任公司部門主管，代表公司向公務機關投標，為使公司順利取得標 案，可以向公務機關的採購人員為以下何種行為？', '為社交禮俗需要，贈 送價值昂貴的名牌手錶作為見面禮,為與公務機關間有良好互動，招待至 有女陪侍場所飲宴,為了解招標文件內容，提出招標文件疑義並請說明,為避免報價錯誤，要求提供底價作為參考 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000778, 'single', '90007', '下列關於政府採購人員之敘述，何者未違反相關規定？', '非主動向廠商求 取，是偶發地收到廠商致贈價值在新臺幣500 元以下之廣告物、促銷品、 紀念品,要求廠商提供與採購無關之額外服務,利用職務關係向廠商借 貸,利用職務關係媒介親友至廠商處所任職 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000779, 'single', '90007', '下列何者有誤？', '憲法保障言論自由，但散布假新聞、假消息仍須面對法 律責任,在網路或Line 社群網站收到假訊息，可以敘明案情並附加截圖 檔，向法務部調查局檢舉,對新聞媒體報導有意見，向國家通訊傳播委員 會申訴,自己或他人捏造、扭曲、竄改或虛構的訊息，只要一小部分能證 明是真的，就不會構成假訊息 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000780, 'single', '90007', '下列敘述何者正確？', '公務機關委託的代檢（代驗）業者，不是公務員， 不會觸犯到刑法的罪責,賄賂或不正利益，只限於法定貨幣，給予網路遊 戲幣沒有違法的問題,在靠北公務員社群網站，覺得可受公評且匿名發 文，就可以謾罵公務機關對特定案件的檢查情形,受公務機關委託辦理案 件，除履行採購契約應辦事項外，對於蒐集到的個人資料，也要遵守相關 保護及保密規定 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000781, 'single', '90007', '下列有關促進參與及預防貪腐的敘述何者錯誤？', '我國非聯合國會員國， 無須落實聯合國反貪腐公約規定,推動政府部門以外之個人及團體積極參 與預防和打擊貪腐,提高決策過程之透明度，並促進公眾在決策過程中發 揮作用,對公職人員訂定執行公務之行為守則或標準 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000782, 'single', '90007', '為建立良好之公司治理制度，公司內部宜納入何種檢舉人制度？', '告訴乃 論制度,吹哨者（whistleblower）保護程序及保護制度,不告不理制度,非告訴乃論制度 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000783, 'single', '90007', '有關公司訂定誠信經營守則時，以下何者不正確？', '避免與涉有不誠信行 為者進行交易,防範侵害營業秘密、商標權、專利權、著作權及其他智慧 財產權,建立有效之會計制度及內部控制制度,防範檢舉 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000784, 'single', '90007', '乘坐轎車時，如有司機駕駛，按照國際乘車禮儀，以司機的方位來看，首 位應為', '後排右側,前座右側,後排左側,後排中間 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000785, 'single', '90007', '今天好友突然來電，想來個「說走就走的旅行」，因此，無法去上班，下 列何者作法不適當？', '打電話給主管與人事部門請假,用LINE 傳訊息給 主管，並確認讀取且有回覆,發送E-MAIL 給主管與人事部門，並收到回 覆,什麼都無需做，等公司打電話來卻認後，再告知即可 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000786, 'single', '90007', '每天下班回家後，就懶得再出門去買菜，利用上班時間瀏覽線上購物網 站，發現有很多限時搶購的便宜商品，還能在下班前就可以送到公司，下 班順便帶回家，省掉好多時間，請問下列何者最適當？', '可以，又沒離開 工作崗位，且能節省時間,可以，還能介紹同事一同團購，省更多的錢， 增進同事情誼,不可以，應該把商品寄回家，不是公司,不可以，上班 不能從事個人私務，應該等下班後再網路購物 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000787, 'single', '90007', '宜樺家中養了一隻貓，由於最近生病，獸醫師建議要有人一直陪牠，這樣 會恢復快一點，因為上班家裡都沒人，所以準備帶牠到辦公室一起上班， 請問下列何者最適當？', '可以，只要我放在寵物箱，不要影響工作即可,可以，同事們都答應也不反對,可以，雖然貓會發出聲音，大小便有異 味，只要處理好不影響工作即可,不可以，建議送至專門機構照護，以免 影響工作 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000788, 'single', '90007', '根據性別平等工作法，下列何者非屬職場性騷擾？', '公司員工執行職務 時，客戶對其講黃色笑話，該員工感覺被冒犯,雇主對求職者要求交往， 作為僱用與否之交換條件,公司員工執行職務時，遭到同事以「女人就是 沒大腦」性別歧視用語加以辱罵，該員工感覺其人格尊嚴受損,公司員工 下班後搭乘捷運，在捷運上遭到其他乘客偷拍 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000789, 'single', '90007', '根據性別平等工作法，下列何者非屬職場性別歧視？', '雇主考量男性賺錢 養家之社會期待，提供男性高於女性之薪資,雇主考量女性以家庭為重之 社會期待，裁員時優先資遣女性,雇主事先與員工約定倘其有懷孕之情 事，必須離職,有未滿2 歲子女之男性員工，也可申請每日六十分鐘的哺 乳時間 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000790, 'single', '90007', '根據性別平等工作法，有關雇主防治性騷擾之責任與罰則，下列何者錯 誤？', '僱用受僱者30 人以上者，應訂定性騷擾防治措施、申訴及懲戒辦 法,雇主知悉性騷擾發生時，應採取立即有效之糾正及補救措施,雇主 違反應訂定性騷擾防治措施之規定時，處以罰鍰即可，不用公布其姓名,雇主違反應訂定性騷擾申訴管道者，應限期令其改善，屆期未改善者，應 按次處罰 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000791, 'single', '90007', '根據性騷擾防治法，有關性騷擾之責任與罰則，下列何者錯誤？', '對他人 為性騷擾者，如果沒有造成他人財產上之損失，就無需負擔金錢賠償之責 任,對於因教育、訓練、醫療、公務、業務、求職，受自己監督、照護之 人，利用權勢或機會為性騷擾者，得加重科處罰鍰至二分之一,意圖性騷 擾，乘人不及抗拒而為親吻、擁抱或觸摸其臀部、胸部或其他身體隱私處 之行為者，處2 年以下有期徒刑、拘役或科或併科10 萬元以下罰金,對 他人為權勢性騷擾以外之性騷擾者，由直轄市、縣（市）主管機關處1 萬 元以上10 萬元以下罰鍰 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000792, 'single', '90007', '根據性別平等工作法規範職場性騷擾範疇，下列何者為「非」？', '上班執 行職務時，任何人以性要求、具有性意味或性別歧視之言詞或行為，造成 敵意性、脅迫性或冒犯性之工作環境,對僱用、求職或執行職務關係受自 己指揮、監督之人，利用權勢或機會為性騷擾,下班回家時被陌生人以盯 梢、守候、尾隨跟蹤,雇主對受僱者或求職者為明示或暗示之性要求、具 有性意味或性別歧視之言詞或行為 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000793, 'single', '90007', '根據消除對婦女一切形式歧視公約（CEDAW）之直接歧視及間接歧視意 涵，下列何者錯誤？', '老闆得知小黃懷孕後，故意將小黃調任薪資待遇較 差的工作，意圖使其自行離開職場，小黃老闆的行為是直接歧視,某餐廳 於網路上招募外場服務生，條件以未婚年輕女性優先錄取，明顯以性或性 別差異為由所實施的差別待遇，為直接歧視,某公司員工值班注意事項排 除女性員工參與夜間輪值，是考量女性有人身安全及家庭照顧等需求，為 維護女性權益之措施，非直接歧視,某科技公司規定男女員工之加班時數 上限及加班費或津貼不同，認為女性能力有限，且無法長時間工作，限制 女性獲取薪資及升遷機會，這規定是直接歧視 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000794, 'single', '90007', '目前菸害防制法規範，「不可販賣菸品」給幾歲以下的人？', '20,19,18,17 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000795, 'single', '90007', '按菸害防制法規定，下列敘述何者錯誤？', '只有老闆、店員才可以出面勸 阻在禁菸場所抽菸的人,任何人都可以出面勸阻在禁菸場所抽菸的人,餐廳、旅館設置室內吸菸室，需經專業技師簽證核可,加油站屬易燃易爆 場所，任何人都可以勸阻在禁菸場所抽菸的人 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000796, 'single', '90007', '關於菸品對人體危害的敘述，下列何者「正確」？', '只要開電風扇、或是 抽風機就可以去除菸霧中的有害物質,指定菸品（如：加熱菸）只要通過 健康風險評估，就不會危害健康，因此工作時如果想吸菸，就可以在職場 拿出來使用,雖然自己不吸菸，同事在旁邊吸菸，就會增加自己得肺癌的 機率,只要不將菸吸入肺部，就不會對身體造成傷害 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000797, 'single', '90007', '職場禁菸的好處不包括', '降低吸菸者的菸品使用量，有助於減少吸菸導致 的健康危害,避免同事因為被動吸菸而生病,讓吸菸者菸癮降低，戒菸 較容易成功,吸菸者不能抽菸會影響工作效率 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000798, 'single', '90007', '大多數的吸菸者都嘗試過戒菸，但是很少自己戒菸成功。吸菸的同事要戒 菸，怎樣建議他是無效的？', '鼓勵他撥打戒菸專線0800-63-63-63，取得 相關建議與協助,建議他到醫療院所、社區藥局找藥物戒菸,建議他參 加醫院或衛生所辦理的戒菸班,戒菸是自己意願的問題，想戒就可以戒了 不用尋求協助 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000799, 'single', '90007', '禁菸場所負責人未於場所入口處設置明顯禁菸標示，要罰該場所負責人多 少元？', '2 千-1 萬,1 萬-5 萬,1 萬-25 萬,20 萬-100 萬 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000800, 'single', '90007', '目前電子煙是非法的，下列對電子煙的敘述，何者錯誤？', '跟吸菸一樣會 成癮,會有爆炸危險,沒有燃燒的菸草，不會造成身體傷害,可能造成 嚴重肺損傷 ', '2', '');